import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long K = fs.nextLong();
            long[] a = new long[N];
            for (int i = 0; i < N; i++) a[i] = fs.nextLong();
            Arrays.sort(a);
            long required = N - K;
            long ans;
            if (required <= 0) ans = a[N - 1];
            else ans = a[N - (int)required];
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is){ in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false; if (c == '-') { neg = true; c = readByte(); }
            long val = 0; while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return neg ? -val : val; }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

